-- ============================================================
-- WordRem — Multi-Language Course Seed
-- Adds FR, DE, ES, IT, RU, ZH courses (native=TR)
-- Run once in your Supabase SQL Editor
-- ============================================================

-- ── STEP 1: Ensure all language rows exist ─────────────────
SELECT v.code, v.name, v.native_name, v.flag_emoji, v.is_active
FROM (VALUES
  ('TR'::varchar, 'Turkish',    'Türkçe',   '🇹🇷', true::boolean),
  ('EN'::varchar, 'English',   'English',   '🇬🇧', true::boolean),
  ('FR'::varchar, 'French',    'Français',  '🇫🇷', true::boolean),
  ('DE'::varchar, 'German',    'Deutsch',   '🇩🇪', true::boolean),
  ('ES'::varchar, 'Spanish',   'Español',   '🇪🇸', true::boolean),
  ('IT'::varchar, 'Italian',   'Italiano',  '🇮🇹', true::boolean),
  ('RU'::varchar, 'Russian',   'Русский',   '🇷🇺', true::boolean),
  ('ZH'::varchar, 'Chinese',   '中文',      '🇨🇳', true::boolean)
) AS v(code, name, native_name, flag_emoji, is_active)
WHERE NOT EXISTS (
  SELECT 1 FROM languages l WHERE UPPER(l.code) = UPPER(v.code)
);

-- ── STEP 2: Courses + Levels + Words ──────────────────────
DO $$
DECLARE
  tr_id INT; fr_id INT; de_id INT;
  es_id INT; it_id INT; ru_id INT; zh_id INT;
BEGIN
  SELECT id INTO tr_id FROM languages WHERE UPPER(code) = 'TR' LIMIT 1;
  SELECT id INTO fr_id FROM languages WHERE UPPER(code) = 'FR' LIMIT 1;
  SELECT id INTO de_id FROM languages WHERE UPPER(code) = 'DE' LIMIT 1;
  SELECT id INTO es_id FROM languages WHERE UPPER(code) = 'ES' LIMIT 1;
  SELECT id INTO it_id FROM languages WHERE UPPER(code) = 'IT' LIMIT 1;
  SELECT id INTO ru_id FROM languages WHERE UPPER(code) = 'RU' LIMIT 1;
  SELECT id INTO zh_id FROM languages WHERE UPPER(code) = 'ZH' LIMIT 1;

  -- ══════════════════════════════════════════════════════════
  -- 🇫🇷 FRENCH COURSE (10 levels × 10 words)
  -- ══════════════════════════════════════════════════════════
  VALUES ('f0000001-0000-0000-0000-000000000001', tr_id, fr_id,
          'Fransızca Temelleri', 'Fransızcayı sıfırdan öğren', 1000, true)
  ON CONFLICT (id) DO NOTHING;

  ON CONFLICT (id) DO NOTHING;

  -- FR Level 1: Greetings
  ON CONFLICT (id) DO NOTHING;
  ON CONFLICT DO NOTHING;

  -- FR Level 2: Numbers
  ON CONFLICT (id) DO NOTHING;
  ON CONFLICT DO NOTHING;

  -- FR Level 3: Colors
  ON CONFLICT (id) DO NOTHING;
  ON CONFLICT DO NOTHING;

  -- FR Level 4: Family
  ON CONFLICT (id) DO NOTHING;
  ON CONFLICT DO NOTHING;

  -- FR Level 5: Food
  ON CONFLICT (id) DO NOTHING;
  ON CONFLICT DO NOTHING;

  -- FR Level 6: Animals
  ON CONFLICT (id) DO NOTHING;
  ON CONFLICT DO NOTHING;

  -- FR Level 7: Days & Time
  ON CONFLICT (id) DO NOTHING;
  ON CONFLICT DO NOTHING;

  -- FR Level 8: Body Parts
  ON CONFLICT (id) DO NOTHING;
  ON CONFLICT DO NOTHING;

  -- FR Level 9: Travel
  ON CONFLICT (id) DO NOTHING;
  ON CONFLICT DO NOTHING;

  -- FR Level 10: Verbs
  ON CONFLICT (id) DO NOTHING;
  ON CONFLICT DO NOTHING;

  -- ══════════════════════════════════════════════════════════
  -- 🇩🇪 GERMAN COURSE (5 levels × 8 words)
  -- ══════════════════════════════════════════════════════════
  VALUES ('de000001-0000-0000-0000-000000000001', tr_id, de_id,
          'Almanca Temelleri', 'Almancayı sıfırdan öğren', 500, true)
  ON CONFLICT (id) DO NOTHING;

  ON CONFLICT (id) DO NOTHING;

  ON CONFLICT (id) DO NOTHING;

  ON CONFLICT DO NOTHING;

  -- ══════════════════════════════════════════════════════════
  -- 🇪🇸 SPANISH COURSE (5 levels × 8 words)
  -- ══════════════════════════════════════════════════════════
  VALUES ('e5000001-0000-0000-0000-000000000001', tr_id, es_id,
          'İspanyolca Temelleri', 'İspanyolcayı sıfırdan öğren', 500, true)
  ON CONFLICT (id) DO NOTHING;

  ON CONFLICT (id) DO NOTHING;

  ON CONFLICT (id) DO NOTHING;

  ON CONFLICT DO NOTHING;

  -- ══════════════════════════════════════════════════════════
  -- 🇮🇹 ITALIAN COURSE (5 levels × 8 words)
  -- ══════════════════════════════════════════════════════════
  VALUES ('17000001-0000-0000-0000-000000000001', tr_id, it_id,
          'İtalyanca Temelleri', 'İtalyancayı sıfırdan öğren', 500, true)
  ON CONFLICT (id) DO NOTHING;

  ON CONFLICT (id) DO NOTHING;

  ON CONFLICT (id) DO NOTHING;

  ON CONFLICT DO NOTHING;

  -- ══════════════════════════════════════════════════════════
  -- 🇷🇺 RUSSIAN COURSE (5 levels × 8 words)
  -- ══════════════════════════════════════════════════════════
  VALUES ('04000001-0000-0000-0000-000000000001', tr_id, ru_id,
          'Rusça Temelleri', 'Rusçayı sıfırdan öğren', 500, true)
  ON CONFLICT (id) DO NOTHING;

  ON CONFLICT (id) DO NOTHING;

  ON CONFLICT (id) DO NOTHING;

  ON CONFLICT DO NOTHING;

  -- ══════════════════════════════════════════════════════════
  -- 🇨🇳 CHINESE COURSE (5 levels × 8 words)
