  ON CONFLICT (id) DO NOTHING;

  ON CONFLICT (id) DO NOTHING;

  ON CONFLICT DO NOTHING;

END $$;

-- ══════════════════════════════════════════════════════════
-- STEP 3: Fix progressive unlocking
-- enrollWithProficiency should only unlock the FIRST level.
-- This function is called from the iOS app.
-- Replace existing enroll_with_proficiency if it unlocks too many.
-- ══════════════════════════════════════════════════════════
CREATE OR REPLACE FUNCTION enroll_with_proficiency(
  p_user_id    UUID,
  p_course_id  UUID,
  p_proficiency INT  -- 0=beginner … 4=advanced (kept for future use)
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_first_level_id UUID;
BEGIN
  -- Find the very first level (order_index = 1) for this course
  SELECT id INTO v_first_level_id
  FROM levels
  WHERE course_id = p_course_id
  ORDER BY order_index ASC
  LIMIT 1;

  IF v_first_level_id IS NULL THEN
    RETURN;  -- No levels found, nothing to unlock
  END IF;

  -- Unlock ONLY the first level regardless of proficiency
  -- (proficiency can affect quiz difficulty in future, not level count)
  VALUES (p_user_id, v_first_level_id, 'unlocked', 0, 0, 0, 0)
  ON CONFLICT (user_id, level_id)
  DO UPDATE SET status = CASE
    WHEN user_progress.status = 'locked' THEN 'unlocked'
    ELSE user_progress.status   -- don't downgrade in_progress/completed
  END;
END;
$$;

-- Grant execute to both anon and authenticated
GRANT EXECUTE ON FUNCTION enroll_with_proficiency(UUID, UUID, INT) TO anon;
GRANT EXECUTE ON FUNCTION enroll_with_proficiency(UUID, UUID, INT) TO authenticated;
